(* ::Input::Initialization:: *)
BeginPackage[
"Ensemble`OrientationalSampling`",
{"Global`","SpinDynamica`","General`Miscellaneous`"}];


(* ::Input::Initialization:: *)
OrientationalSamplingScheme::usage="OrientationalSamplingScheme[] lists all available orientational sampling schemes. OrientationalSamplingScheme[name] returns the information associated with a particular scheme.";


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme::usage="DefineOrientationalSamplingScheme[name, specifications] or DefineOrientationalSamplingScheme[name,info,specifications] defines an orientational sampling scheme with a certain name, and (optional) associated information. specifications may be a set of Euler angles and weights, of the form {{{\[Alpha],\[Beta],\[Gamma]},w}..} where the weights must sum to 1. specifications may also be a function returning a set of Euler angles and weights, when evaluated with certain parameters.";


(* ::Input::Initialization:: *)
Orientations::usage="Orientations[name] generates the orientations for a named orientational sampling scheme.";


(* ::Input::Initialization:: *)
OrientationsAndWeights::usage="OrientationsAndWeights[<name>] generates the orientations and weights for a named orientational sampling scheme. The orientations are specified as Euler angle triplets {{\[Alpha]1,\[Beta]1,\[Gamma]1},..}.\nOrientationsAndWeights[<scheme>]  may be used to generate a powder average for top-level SpinDynamica routines such as Signal1D, Trajectory, TransformationAmplitude, etc. using syntax of the form Signal1D[<<arguments>>, EnsembleAverage\[Rule]{{\[Alpha],\[Beta],\[Gamma]},OrientationsAndWeights[<scheme>]}] where any of the arguments of Signal1D may depend on the Euler angles \[Alpha], \[Beta], or \[Gamma]. 
The syntax EnsembleAverage\[Rule]{\[CapitalOmega],OrientationsAndWeights[<scheme>]} may also be used. In this case the orientational variable \[CapitalOmega] takes values given by the Euler angles sets {\[Alpha],\[Beta],\[Gamma]} specified within the scheme. Any of the arguments of Signal1D may depend on \[CapitalOmega].
In most cases, OrientationsAndWeights[<name>] is sufficient to specify the sampling scheme fully. In some cases, additional arguments are needed. Execute OrientationsAndWeights[<name>] to obtain this information. 
";


(* ::Input::Initialization:: *)
OrientationWeights::usage="OrientationWeights[name] generates the weights for a named orientational sampling scheme.";


(* ::Input::Initialization:: *)
BetaAnglesAndWeights::usage="BetaAnglesAndWeights[name] generates the set of \[Beta] angles and weights for a named orientational sampling scheme.";


(* ::Input::Initialization:: *)
Begin["`Private`"];


(* ::Input::Initialization:: *)
DefinedOrientationalSamplingSchemes={};


(* ::Input::Initialization:: *)
OrientationalSamplingSchemeInformation[_]:=None;


(* ::Input::Initialization:: *)
ValidWeightsQ[oss:{{{_,_,_},_}...}]:=Chop@N[Plus@@(Last/@oss)-1]==0;


(* ::Input::Initialization:: *)
CorrectWeights[oss:{{{_,_,_},_}...}]:=
Module[{euler,weights,sum},(
{euler,weights}=Transpose[oss];
sum=Plus@@weights;
Transpose[{euler,weights/sum}]
)];


OrientationalSamplingSchemeInformation[name_String]:=OrientationalSamplingSchemeInformation[name,OrientationalSamplingScheme];


OrientationalSamplingSchemeInformation[name_String,OrientationsAndWeights|Orientations]:=OrientationalSamplingSchemeInformation[name,OrientationalSamplingScheme]


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme[name_String,info___String,specs:({{{_,_,_},_}...}|_Function)]:=(Message[DefineOrientationalSamplingScheme::dup,name];
DefinedOrientationalSamplingSchemes=Cases[DefinedOrientationalSamplingSchemes,Except[name]];
DefineOrientationalSamplingScheme[name,info,specs];
)/;MemberQ[DefinedOrientationalSamplingSchemes,name]


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme[name__String,info_,oss:{{{_,_,_},_}...}]:=
(Message[DefineOrientationalSamplingScheme::badweights,name];$Failed)/;!ValidWeightsQ[oss];


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme[name__String,info_String,oss:{{{_,_,_},_}...}]:=
DefineOrientationalSamplingScheme[name,{info,info},oss];


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme[name__String,{geninfo_String,\[Beta]info_String},oss:{{{_,_,_},_}...}]:=
(OrientationalSamplingSchemeInformation[name,OrientationalSamplingScheme]=geninfo;
OrientationalSamplingSchemeInformation[name,BetaAnglesAndWeights]=\[Beta]info;
DefineOrientationalSamplingScheme[name,oss]
);


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme[name__String,oss:{{{_,_,_},_}...}]:=
(OrientationsAndWeights[name]=oss;
DefinedOrientationalSamplingSchemes=Sort@Append[DefinedOrientationalSamplingSchemes,name];
Message[DefineOrientationalSamplingScheme::def,name,Length[oss]];
name
);


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme[name__String,info_String,{f_Function,{patterns___}}]:=
DefineOrientationalSamplingScheme[name,{info,info},{f,{patterns}}]


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme[name__String,{geninfo_String,\[Beta]info_String},{f_Function,{patterns___}}]:=
(OrientationalSamplingSchemeInformation[name]=geninfo;
OrientationalSamplingSchemeInformation[name,BetaAnglesAndWeights]=\[Beta]info;
DefineOrientationalSamplingScheme[name,{f,{patterns}}]
);


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme[name_String,{f_Function,{patterns___}}]:=
(
OrientationsAndWeights[name,pars___]:=
If[
MatchQ[{pars},{patterns}],
f[pars],
(Message[OrientationalSamplingScheme::badsyntax,name];
Print[OrientationalSamplingSchemeInformation[name]];
$Failed)
];
BetaAnglesAndWeights[name,pars___]:=
If[
MatchQ[{pars},{patterns}],
{#[[1,2]],#[[2]]}&/@OrientationsAndWeights[name,pars],
(Message[OrientationalSamplingScheme::badsyntax,name];
Print[OrientationalSamplingSchemeInformation[name,BetaAnglesAndWeights]];
$Failed)
];
DefinedOrientationalSamplingSchemes=Sort@Append[DefinedOrientationalSamplingSchemes,name];
Message[DefineOrientationalSamplingScheme::fdef,name];
name
);


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme::def="OrientationalSamplingScheme `1` with dimension `2` defined.";


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme::fdef="The OrientationalSamplingScheme function `1` has been defined.";


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme::dup="OrientationalSamplingScheme `1` is already defined. It is being superseded.";


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme::badweights="The weights for OrientationalSamplingScheme  `1` do not sum to 1. The scheme has not been defined.";


(* ::Input::Initialization:: *)
OrientationalSamplingScheme[]:=Print["Predefined orientational sampling schemes:",DefinedOrientationalSamplingSchemes,
"Execute OrientationalSamplingScheme[<scheme>] for the usage message of a sampling scheme. Note that <scheme> must be a string enclosed by quotes, for example \"Leboct10\"."
];


(* ::Input::Initialization:: *)
OrientationalSamplingScheme[name_String]:=OrientationalSamplingSchemeInformation[name];


(* ::Input::Initialization:: *)
OrientationalSamplingScheme::undef="OrientationalSamplingScheme `1` is undefined. The defined schemes are given below. Note that the name of the scheme must be a string enclosed by quotes, for example \"Leboct10\".";


(* ::Input::Initialization:: *)
OrientationalSamplingScheme::badsyntax="Incorrect syntax for the OrientationalSamplingScheme `1`";


(* ::Input::Initialization:: *)
Orientations[]:=OrientationalSamplingScheme[];


(* ::Input::Initialization:: *)
Orientations[name_String,pars___]/;!MemberQ[DefinedOrientationalSamplingSchemes,name]:=(Message[OrientationalSamplingScheme::undef,name];OrientationalSamplingScheme[]);


(* ::Input::Initialization:: *)
Orientations[name_String,pars___]/;MemberQ[DefinedOrientationalSamplingSchemes,name]:=First/@OrientationsAndWeights[name,pars];


(* ::Input::Initialization:: *)
OrientationWeights[]:=OrientationalSamplingScheme[];


(* ::Input::Initialization:: *)
OrientationWeights[name_String,pars___]/;!MemberQ[DefinedOrientationalSamplingSchemes,name]:=(Message[OrientationalSamplingScheme::undef,name];OrientationalSamplingScheme[]);


(* ::Input::Initialization:: *)
OrientationWeights[name_String,pars___]/;MemberQ[DefinedOrientationalSamplingSchemes,name]:=Last/@OrientationsAndWeights[name,pars];


(* ::Input::Initialization:: *)
OrientationsAndWeights[]:=OrientationalSamplingScheme[];


(* ::Input::Initialization:: *)
OrientationsAndWeights[name_String,pars___]/;!MemberQ[DefinedOrientationalSamplingSchemes,name]:=(Message[OrientationalSamplingScheme::undef,name];OrientationalSamplingScheme[]);


(* ::Input::Initialization:: *)
BetaAnglesAndWeights[]:=OrientationalSamplingScheme[];


(* ::Input::Initialization:: *)
BetaAnglesAndWeights[name_String,pars___]/;!MemberQ[DefinedOrientationalSamplingSchemes,name]:=(Message[OrientationalSamplingScheme::undef,name];OrientationalSamplingScheme[]);


