Off[DefineOrientationalSamplingScheme::"def",DefineOrientationalSamplingScheme::"fdef"];


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme["Step\[Beta]",
{"OrientationsAndWeights[\"Step\[Beta]\", n, {\[Beta]min,\[Beta]max}] generates a set of n Sin\[Beta]-weighted orientations {\[Alpha],\[Beta],\[Gamma]}, with \[Alpha] and \[Gamma] equal to 0, and with \[Beta] stepping linearly over the specified range. 
The appropriate syntax is f[<args>, EnsembleAverage->{{\[Alpha],\[Beta],\[Gamma]},OrientationsAndWeights[\"Step\[Beta]\",n,{\[Beta]min,\[Beta]max}]], where f is a high-level SpinDynamica routine such as Signal1D, etc. The arguments <args> of the calling routine only depend on the angle \[Beta]. ",
"BetaAnglesAndWeights[\"Step\[Beta]\", n, {\[Beta]min,\[Beta]max}] generates a set of n suitably weighted \[Beta] angles, with \[Beta] stepping linearly over the specified range."
},
{
Function[{n,\[Beta]range},(
Module[{\[Delta]\[Beta],\[Beta]min,\[Beta]max,\[Beta]vals,weights},(
{\[Beta]min,\[Beta]max}=\[Beta]range;
\[Delta]\[Beta]=(\[Beta]max-\[Beta]min)/n;
\[Beta]vals=Range[\[Beta]min+\[Delta]\[Beta]/2,\[Beta]max-\[Delta]\[Beta]/2,\[Delta]\[Beta]];
weights=(Sin/@\[Beta]vals)/Plus@@(Sin/@\[Beta]vals);
N@MapThread[{{0,#1,0},#2}&,{\[Beta]vals,weights}]
)]
)],
{_Integer,{_?NumericQ,_?NumericQ}}
}
];


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme["Step\[Alpha]\[Beta]",
"OrientationsAndWeights[\"Step\[Alpha]\[Beta]\", n\[Alpha], n\[Beta]] generates a set of n Sin\[Beta]-weighted orientations {\[Alpha],\[Beta],\[Gamma]}, with \[Gamma] equal to 0, with \[Alpha] stepping over the range [0,2\[Pi]] in n\[Alpha] steps, and \[Beta] stepping over the range [0,\[Pi]] in n\[Beta] steps. 
The appropriate syntax is f[<args>, EnsembleAverage->{{\[Alpha],\[Beta],\[Gamma]},OrientationsAndWeights[\"Step\[Alpha]\[Beta]\",n\[Alpha], n\[Beta]]], where f is a high-level SpinDynamica routine such as Signal1D, etc. The arguments <args> of the calling routine only depend on the angles \[Alpha] and \[Beta]. ",
{
Function[{n\[Alpha],n\[Beta]},(
Module[{\[Delta]\[Alpha],\[Alpha]min,\[Alpha]max,\[Delta]\[Beta],\[Beta]min,\[Beta]max,\[Alpha]vals,\[Beta]vals,\[CapitalOmega]vals,weights},(
{\[Alpha]min,\[Alpha]max}={0,2\[Pi]};
{\[Beta]min,\[Beta]max}={0,\[Pi]};
\[Delta]\[Alpha]=(\[Alpha]max-\[Alpha]min)/n\[Alpha];\[Delta]\[Beta]=(\[Beta]max-\[Beta]min)/n\[Beta];
\[Beta]vals=Range[\[Beta]min+\[Delta]\[Beta]/2,\[Beta]max-\[Delta]\[Beta]/2,\[Delta]\[Beta]];
\[Alpha]vals=Range[\[Alpha]min+\[Delta]\[Alpha]/2,\[Alpha]max-\[Delta]\[Alpha]/2,\[Delta]\[Alpha]];
\[CapitalOmega]vals=Flatten[Outer[{#1,#2,0}&,\[Alpha]vals,\[Beta]vals],1];
weights=Module[{sin\[Beta]vals},(sin\[Beta]vals=(Sin[#[[2]]]&/@\[CapitalOmega]vals);sin\[Beta]vals/Plus@@sin\[Beta]vals)];
N@MapThread[{#1,#2}&,{\[CapitalOmega]vals,weights}]
)]
)],
{_Integer,_Integer}
}
];


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme["Random\[Beta]",
{"OrientationsAndWeights[\"Random\[Beta]\", n] generates a set of n uniformly weighted {\[Alpha],\[Beta],\[Gamma]} orientations, with \[Alpha] and \[Gamma] equal to 0, and randomly chosen \[Beta] angles in the range [0,\[Pi]] (distributed according to a Sin[\[Beta]] probability function). 
The appropriate syntax is f[<args>, EnsembleAverage->{{\[Alpha],\[Beta],\[Gamma]},OrientationsAndWeights[\"Random\[Beta]\",n]], where f is a high-level SpinDynamica routine such as Signal1D, etc. The arguments <args> of the calling routine only depend on the angle \[Beta]. ",
"BetaAnglesAndWeights[\"Random\[Beta]\", n] generates a set of n randomly chosen \[Beta] angles in the range [0,\[Pi]]."
},
{
Function[{n},(
Module[{\[Beta]vals,weights},(
\[Beta]vals=Table[ArcCos[RandomReal[{-1,1}]],{n}];
weights=Table[1/n,{n}];
N@MapThread[{{0,#1,0},#2}&,{\[Beta]vals,weights}]
)]
)],
{_Integer}
}
];


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme["Random\[Alpha]\[Beta]",
"OrientationsAndWeights[\"Random\[Alpha]\[Beta]\", n] generates a set of uniformly weighted {\[Alpha],\[Beta],\[Gamma]} orientations, with \[Gamma] equal to 0, while the \[Alpha] and \[Beta] angles are chosen randomly in the range [0,2\[Pi]] for \[Alpha] and [0,\[Pi]] for \[Beta]. The \[Beta] angles are distributed according to a Sin[\[Beta]] probability function. 
The appropriate syntax is f[<args>, EnsembleAverage->{{\[Alpha],\[Beta],\[Gamma]},OrientationsAndWeights[\"Random\[Alpha]\[Beta]\", n]], where f is a high-level SpinDynamica routine such as Signal1D, etc. The arguments <args> of the calling routine only depend on the angles \[Alpha] and \[Beta].",
{
Function[{n},(
Module[{\[Alpha]vals,\[Beta]vals,weights},(
\[Alpha]vals=Table[RandomReal[{0,2\[Pi]}],{n}];
\[Beta]vals=Table[ArcCos[RandomReal[{-1,1}]],{n}];
weights=Table[1/n,{n}];
N@MapThread[{{#1,#2,0},#3}&,{\[Alpha]vals,\[Beta]vals,weights}]
)]
)],
{_Integer}
}
];


(* ::Input::Initialization:: *)
DefineOrientationalSamplingScheme["Random\[Alpha]\[Beta]\[Gamma]",
"OrientationsAndWeights[\"Random\[Alpha]\[Beta]\[Gamma]\", n] generates a set of uniformly weighted {\[Alpha],\[Beta],\[Gamma]} orientations, with \[Alpha] and \[Gamma] randomly chosen in the range [0,2\[Pi]], and \[Beta] randomly chosen in the range [0,\[Pi]], distributed according to a Sin[\[Beta]] probability function.
The appropriate syntax is f[<args>, EnsembleAverage->{{\[Alpha],\[Beta],\[Gamma]},OrientationsAndWeights[\"Random\[Alpha]\[Beta]\[Gamma]\", n]], where f is a high-level SpinDynamica routine such as Signal1D, etc. The arguments <args> of the calling routine may depend on the angles \[Alpha], \[Beta] and \[Gamma].",
{
Function[{n},(
Module[{\[Alpha]vals,\[Beta]vals,\[Gamma]vals,weights},(
\[Alpha]vals=Table[RandomReal[{0,2\[Pi]}],{n}];
\[Beta]vals=Table[ArcCos[RandomReal[{-1,1}]],{n}];
\[Gamma]vals=Table[RandomReal[{0,2\[Pi]}],{n}];
weights=Table[1/n,{n}];
N@MapThread[{{#1,#2,#3},#4}&,{\[Alpha]vals,\[Beta]vals,\[Gamma]vals,weights}]
)]
)],
{_Integer}
}
];


